  {"Id":"00TWt000002yzp8MAA","WhatId":"006Wt000007BGGjIAO","OwnerId":"005Wt000003NF9WIAW","Priority":"Normal","Status":"Not Started ","ActivityDate":"2022-02-15","Subject":"Follow up on proposal","Description":"Reach out to the client to address any questions and negotiate terms"},
  {"Id":"00TWt000002z4fFMAQ","WhatId":"006Wt000007BGGjIAO","OwnerId":"#005Wt000003NIc1IAG","Priority":"High","Status":"Not Started","ActivityDate":"2022-02-10","Subject":"Hold negotiation meeting","Description":"Discuss terms and finalize pricing with the client"}
]
# Analyze tasks to determine stage
def infer_stage(tasks):
    has_demo = False
    has_proposal = False
    has_negotiation = False
    for t in tasks:
        subject = t.get('Subject', '').lower()
        desc = t.get('Description', '').lower()
        if 'demo' in subject or 'demo' in desc:
            has_demo = True
        if 'proposal' in subject or 'proposal' in desc:
            has_proposal = True
        if 'negotiation' in subject or 'negotiate' in desc or 'pricing' in desc:
            has_negotiation = True
    # Determine most appropriate stage based on activities
    if has_negotiation:
        return 'Negotiation'
    elif has_proposal:
        return 'Quote'
    elif has_demo:
        return 'Discovery'
    else:
        return 'Qualification'

stage = infer_stage(tasks)
print('__RESULT__:')
print(json.dumps(stage))

